package com.hogaria.entity;import jakarta.persistence.*;import lombok.*;import org.hibernate.annotations.CreationTimestamp;import org.hibernate.annotations.UpdateTimestamp;import java.time.*;import java.util.*;
@Entity @Table(name="habit") @Data @Builder @NoArgsConstructor @AllArgsConstructor public class Habit { @Id @GeneratedValue private UUID id; private UUID profileId; private String name; private String description; private String area; @Enumerated(EnumType.STRING) private HabitFrequency frequency; private Boolean active; @CreationTimestamp private LocalDateTime createdAt; @UpdateTimestamp private LocalDateTime updatedAt; }
